  rangeOfMeaning:["burnt offering","peace/fellowship offering","sin offering","trespass offering","grain offering","Christ's sacrifice","believer's living sacrifice","praise as sacrifice (Heb 13:15)"],notMean:"Not undifferentiated bloodshed.",
  cultural:"Edersheim's Temple Ministry (project source) describes the daily TAMID, festival sacrifices, and altar liturgy.",
  kingdomSignificance:"Christ's once-for-all sacrifice opens kingdom access (Heb 10:19-22).",
  relatedVerses:["Genesis 4:3-4","Genesis 22","Leviticus 1-7","Leviticus 16","1 Samuel 15:22","Psalm 40:6-8","Psalm 51:16-17","Isaiah 53","Hosea 6:6","Matthew 9:13","John 1:29","Romans 3:25","Romans 12:1","Ephesians 5:2","Hebrews 9-10","Hebrews 13:15-16","1 Peter 2:5"],
  relatedWords:["altar","blood","priest","atonement","propitiation"],category:"worship / temple",
