  rangeOfMeaning:["graven image","household-god","heart-idol","greed-as-idol"],
  relatedVerses:["Exodus 20:3-6","1 Corinthians 8","1 Corinthians 10:14-22","2 Corinthians 6:16","Colossians 3:5","1 Thessalonians 1:9","1 John 5:21","Revelation 9:20"],
